 1	import type { FC } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import { Button, ButtonVariant, DataList } from '@patternfly/react-core';
 5	import { PlusCircleIcon } from '@patternfly/react-icons';
 6	
 7	import type { Mapping } from '../utils/types';
 8	
 9	import { MappingListItem } from './MappingListItem';
10	
11	type MappingListProps = {
12	  mappings: Mapping[];
13	  availableSources?: string[];
14	  availableDestinations?: string[];
15	  additionalDestinations?: string[];
16	  replaceMapping?: (val: { current: Mapping; next: Mapping }) => void;
17	  deleteMapping?: (mapping: Mapping) => void;
18	  addMapping?: () => void;
19	  generalSourcesLabel: string;
20	  noSourcesLabel: string;
21	  isDisabled?: boolean;
22	  isEditable?: boolean;
23	  testId?: string;
24	};
25	
26	const MappingList: FC<MappingListProps> = ({
27	  additionalDestinations,
28	  addMapping,
29	  availableDestinations,
30	  availableSources,
31	  deleteMapping,
32	  generalSourcesLabel,
33	  isDisabled = false,
34	  isEditable = true,
35	  mappings,
36	  noSourcesLabel,
37	  replaceMapping,
38	  testId,
39	}) => {
40	  const { t } = useForkliftTranslation();
41	
42	  return (
43	    <>
44	      <DataList isCompact aria-label="" data-testid={testId}>
45	        {mappings?.map(({ destination, source }, index) => (
46	          <MappingListItem
47	            source={source}
48	            destination={destination}
49	            sources={availableSources}
50	            destinations={availableDestinations}
51	            additionalDestinations={additionalDestinations}
52	            replaceMapping={replaceMapping}
53	            deleteMapping={deleteMapping}
54	            index={index}
55	            key={`${source}-${destination}`}
56	            generalSourcesLabel={generalSourcesLabel}
57	            noSourcesLabel={noSourcesLabel}
58	            isEditable={isEditable}
59	            testId={testId}
60	          />
61	        ))}
62	      </DataList>
63	      {isEditable && (
64	        <Button
65	          onClick={addMapping}
66	          type="button"
67	          variant={ButtonVariant.link}
68	          isDisabled={isDisabled}
69	          icon={<PlusCircleIcon />}
70	          data-testid={
71	            testId ? `add-${testId.replace('-mappings-list', '')}-mapping-button` : undefined
72	          }
73	        >
74	          {t('Add mapping')}
75	        </Button>
76	      )}
77	    </>
78	  );
79	};
80	
81	export default MappingList;

