20	import { MinusCircleIcon } from '@patternfly/react-icons';
21	
22	import type { Mapping } from '../utils/types';
23	
24	import SelectedOptions from './SelectedOptions';
25	
26	type MappingListItemProps = {
27	  source: string;
28	  destination: string;
29	  sources?: string[];
30	  destinations?: string[];
31	  additionalDestinations?: string[];
32	  generalSourcesLabel: string;
33	  noSourcesLabel: string;
34	  index: number;
35	  replaceMapping?: (val: { current: Mapping; next: Mapping }) => void;
36	  deleteMapping?: (mapping: Mapping) => void;
37	  isEditable: boolean;
38	  testId?: string;
39	};
40	
41	export const MappingListItem: FC<MappingListItemProps> = ({
42	  additionalDestinations,
43	  deleteMapping,
44	  destination,
45	  destinations,
46	  generalSourcesLabel,
47	  index,
48	  isEditable,
49	  noSourcesLabel,
50	  replaceMapping,
51	  source,
52	  sources,
53	  testId,
54	}) => {
55	  const { t } = useForkliftTranslation();
56	  const [isSrcOpen, setIsSrcOpen] = useState(false);
57	  const [isTrgOpen, setIsTrgOpen] = useState(false);
58	  const [srcSelected, setSrcSelected] = useState<string>(source);
59	  const [trgSelected, setTrgSelected] = useState<string>(destination);
60	
61	  const onSrcToggleClick = () => {
62	    setIsSrcOpen(!isSrcOpen);
63	  };
64	
65	  const onTrgToggleClick = () => {
66	    setIsTrgOpen(!isTrgOpen);
67	  };
68	
69	  const toggle =
70	    (selected: string, isOpen: boolean, onToggleClick: () => void) =>
71	    (toggleRef: Ref<MenuToggleElement>) => (
72	      <MenuToggle
73	        ref={toggleRef}
74	        onClick={onToggleClick}
75	        isExpanded={isOpen}
76	        isDisabled={!isEditable}
77	        isFullWidth
78	      >
79	        {selected}
80	      </MenuToggle>

